import java.util.Scanner;

public class RestaurantBilling {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        System.out.print("Number of items: ");
        int count = sc.nextInt();
        sc.nextLine();

        double subtotal = 0;
        for (int i = 1; i <= count; i++) {
            System.out.print("Item " + i + " name: ");
            String name = sc.nextLine();
            System.out.print("Price: ");
            double price = sc.nextDouble();
            sc.nextLine();
            subtotal += price;
            System.out.printf("  %s - Rs. %.2f%n", name, price);
        }

        double discountPercent = subtotal > 1000 ? 10 : (subtotal > 500 ? 5 : 0);
        double discount = subtotal * discountPercent / 100.0;
        double afterDiscount = subtotal - discount;
        double tax = afterDiscount * 0.05;
        double grandTotal = afterDiscount + tax;

        System.out.println("\n--- Bill ---");
        System.out.printf("Subtotal  : Rs. %.2f%n", subtotal);
        System.out.printf("Discount  : Rs. %.2f (%g%%)%n", discount, discountPercent);
        System.out.printf("Tax (5%%)  : Rs. %.2f%n", tax);
        System.out.printf("Grand Total: Rs. %.2f%n", grandTotal);

        sc.close();
    }
}
